index fdef49e310f8..0c1aa672bf98 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -811,13 +811,25 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
     Value *X;
     const APInt *C1;
     Constant *C2;
-    if (match(Src, m_OneUse(m_Shr(m_Shl(m_Power2(C1), m_Value(X)),
-                                  m_ImmConstant(C2))))) {
+    if (match(Src, m_Shr(m_Shl(m_Power2(C1), m_Value(X)),
+                                  m_ImmConstant(C2)))) {
       // trunc ((C1 << X) >> C2) to i1 --> X == (C2-cttz(C1)), where C1 is pow2
       Constant *Log2C1 = ConstantInt::get(SrcTy, C1->exactLogBase2());
       Constant *CmpC = ConstantExpr::getSub(C2, Log2C1);
       return new ICmpInst(ICmpInst::ICMP_EQ, X, CmpC);
     }
+    if (match(Src, m_Shr(m_Power2(C1), m_Value(X)))) {
+      // trunc (lshr Pow2, X) to i1 --> X == log2(Pow2)
+      Constant *Log2C1 = ConstantInt::get(SrcTy, C1->exactLogBase2());
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C1);
+    }
+    const APInt *Mask;
+    if (match(Src, m_Shr(m_APInt(Mask), m_Value(X))) && Mask->isMask()) {
+      // trunc (lshr (2^k - 1), X) to i1 --> icmp ult X, k
+      unsigned K = Mask->countTrailingOnes();
+      Constant *Limit = ConstantInt::get(SrcTy, K);
+      return new ICmpInst(ICmpInst::ICMP_ULT, X, Limit);
+    }

